package com.hospital.management.controller.admin;import com.hospital.management.model.Department;import com.hospital.management.service.*;import com.hospital.management.service.impl.DepartmentServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;import java.util.Optional;
@WebServlet("/admin/departments/view")public class DepartmentViewServlet extends HttpServlet{private final DepartmentService service;public DepartmentViewServlet(){this(new DepartmentServiceImpl());}public DepartmentViewServlet(DepartmentService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=Form.id(q.getParameter("id"));if(id==null){r.sendError(400);return;}Optional<Department>d=service.getDepartment(id);if(d.isEmpty()){r.sendError(404);return;}q.setAttribute("department",d.get());q.getRequestDispatcher("/WEB-INF/views/admin/departments/view.jsp").forward(q,r);}}
